type Field = { name: string; label: string; type?: 'text' | 'number' | 'date' | 'datetime' | 'textarea' | 'select' | 'boolean' | 'array' | 'json' | 'reference' | 'password' | 'image'; options?: string[]; reference?: string; required?: boolean };

function toLocalDateTimeInput(value: unknown) {
  const date = new Date(String(value));
  if (Number.isNaN(date.getTime())) return '';
  const local = new Date(date.getTime() - date.getTimezoneOffset() * 60_000);
  return local.toISOString().slice(0, 16);
}

